use crate::types::{DecideInput, DecideOutput};
use std::convert::TryInto;
use std::f64::consts::PI;

pub fn decide(input: &DecideInput) -> DecideOutput {
    let mut cmv = vec![false; 15];
    let mut pum = vec![vec![false; 15]; 15];
    let mut fuv = vec![false; 15];

    cmv[0] = lic1(input);
    cmv[1] = lic2(input);
    cmv[2] = lic3(input);
    cmv[3] = lic4(input);
    cmv[4] = lic5(input);
    cmv[5] = lic6(input);
    cmv[6] = lic7(input);
    cmv[7] = lic8(input);
    cmv[8] = lic9(input);
    cmv[9] = lic10(input);
    cmv[10] = lic11(input);
    cmv[11] = lic12(input);
    cmv[12] = lic13(input);
    cmv[13] = lic14(input);
    cmv[14] = lic15(input);

    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                let connector = &input.lcm[i][j];
                match connector.as_str() {
                    "NOTUSED" => pum[i][j] = true,
                    "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                    "ORR" => pum[i][j] = cmv[i] || cmv[j],
                    _ => pum[i][j] = true,
                }
            }
        }
    }

    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if !pum[i][j] {
                    all_true = false;
                    break;
                }
            }
            fuv[i] = all_true;
        }
    }

    let launch = fuv.iter().all(|&x| x);

    let cmv_arr: [bool; 15] = cmv.try_into().unwrap();
    let fuv_arr: [bool; 15] = fuv.try_into().unwrap();
    let mut pum_arr: [[bool; 15]; 15] = [[false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            pum_arr[i][j] = pum[i][j];
        }
    }

    DecideOutput::from_fixed(cmv_arr, pum_arr, fuv_arr, launch)
}

fn realcompare(a: f64, b: f64) -> &'static str {
    if a == b {
        return "EQ";
    }

    let diff = (a - b).abs();
    let max_ab = a.abs().max(b.abs());

    let tolerance = if max_ab == 0.0 { 1e-6 } else { max_ab * 1e-6 };

    if diff <= tolerance {
        "EQ"
    } else if a < b {
        "LT"
    } else {
        "GT"
    }
}

fn lic1(input: &DecideInput) -> bool {
    let length1 = input.parameters.length1;
    for i in 0..input.numpoints - 1 {
        let dx = input.x[i + 1] - input.x[i];
        let dy = input.y[i + 1] - input.y[i];
        let dist = (dx * dx + dy * dy).sqrt();
        if realcompare(dist, length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic2(input: &DecideInput) -> bool {
    let radius1 = input.parameters.radius1;
    for i in 0..input.numpoints - 2 {
        let p1 = (input.x[i], input.y[i]);
        let p2 = (input.x[i + 1], input.y[i + 1]);
        let p3 = (input.x[i + 2], input.y[i + 2]);

        if !can_contain_in_circle(p1, p2, p3, radius1) {
            return true;
        }
    }
    false
}

fn can_contain_in_circle(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64), radius: f64) -> bool {
    let (x1, y1) = p1;
    let (x2, y2) = p2;
    let (x3, y3) = p3;

    let d12 = (x2 - x1).powi(2) + (y2 - y1).powi(2);
    let d23 = (x3 - x2).powi(2) + (y3 - y2).powi(2);
    let d13 = (x3 - x1).powi(2) + (y3 - y1).powi(2);

    if d12 == 0.0 && d23 == 0.0 && d13 == 0.0 {
        return realcompare(radius, 0.0) != "LT";
    }

    let a = x1 * (y2 - y3) - x2 * (y1 - y3) + x3 * (y1 - y2);
    let two_a = 2.0 * a;

    if realcompare(two_a, 0.0) == "EQ" {
        let mid_x = (x1 + x2 + x3) / 3.0;
        let mid_y = (y1 + y2 + y3) / 3.0;
        let d1_sq = (x1 - mid_x).powi(2) + (y1 - mid_y).powi(2);
        let d2_sq = (x2 - mid_x).powi(2) + (y2 - mid_y).powi(2);
        let d3_sq = (x3 - mid_x).powi(2) + (y3 - mid_y).powi(2);
        let max_dist_sq = if realcompare(d1_sq, d2_sq) == "GT" {
            if realcompare(d1_sq, d3_sq) == "GT" {
                d1_sq
            } else {
                d3_sq
            }
        } else {
            if realcompare(d2_sq, d3_sq) == "GT" {
                d2_sq
            } else {
                d3_sq
            }
        };
        return realcompare(max_dist_sq.sqrt(), radius) != "GT";
    }

    let bx = ((y2 - y1) * (y3 - y1) * (y3 - y2) - (x2 - x1) * (x3 - x1) * (x3 - x2)) / two_a;
    let by = ((x3 - x2) * (x1 * (y3 - y2) - y1 * (x3 - x2))
        - (x2 - x1) * (x3 * (y2 - y1) - y3 * (x2 - x1)))
        / two_a;

    let cx = x1 - bx;
    let cy = y1 - by;

    let center_x = x1 + bx;
    let center_y = y1 + by;

    let d1 = ((x1 - center_x).powi(2) + (y1 - center_y).powi(2)).sqrt();
    let d2 = ((x2 - center_x).powi(2) + (y2 - center_y).powi(2)).sqrt();
    let d3 = ((x3 - center_x).powi(2) + (y3 - center_y).powi(2)).sqrt();

    realcompare(d1, radius) != "GT"
        && realcompare(d2, radius) != "GT"
        && realcompare(d3, radius) != "GT"
}

fn lic3(input: &DecideInput) -> bool {
    let epsilon = input.parameters.epsilon;
    for i in 0..input.numpoints - 2 {
        let p1 = (input.x[i], input.y[i]);
        let p2 = (input.x[i + 1], input.y[i + 1]);
        let p3 = (input.x[i + 2], input.y[i + 2]);

        if p1 == p2 || p2 == p3 {
            continue;
        }

        let angle = compute_angle(p1, p2, p3);

        if realcompare(angle, PI - epsilon) == "LT" || realcompare(angle, PI + epsilon) == "GT" {
            return true;
        }
    }
    false
}

fn compute_angle(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    let (x1, y1) = p1;
    let (x2, y2) = p2;
    let (x3, y3) = p3;

    let v1x = x1 - x2;
    let v1y = y1 - y2;
    let v2x = x3 - x2;
    let v2y = y3 - y2;

    let dot = v1x * v2x + v1y * v2y;
    let mag1 = (v1x * v1x + v1y * v1y).sqrt();
    let mag2 = (v2x * v2x + v2y * v2y).sqrt();

    if realcompare(mag1, 0.0) == "EQ" || realcompare(mag2, 0.0) == "EQ" {
        return PI;
    }

    let cos_angle = dot / (mag1 * mag2);
    let cos_angle = cos_angle.max(-1.0).min(1.0);
    cos_angle.acos()
}

fn lic4(input: &DecideInput) -> bool {
    let area1 = input.parameters.area1;
    for i in 0..input.numpoints - 2 {
        let p1 = (input.x[i], input.y[i]);
        let p2 = (input.x[i + 1], input.y[i + 1]);
        let p3 = (input.x[i + 2], input.y[i + 2]);

        let area = triangle_area(p1, p2, p3);
        if realcompare(area, area1) == "GT" {
            return true;
        }
    }
    false
}

fn triangle_area(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    let (x1, y1) = p1;
    let (x2, y2) = p2;
    let (x3, y3) = p3;

    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0).abs()
}

fn lic5(input: &DecideInput) -> bool {
    let q_pts = input.parameters.q_pts;
    let quads = input.parameters.quads;

    if q_pts > input.numpoints {
        return false;
    }

    for i in 0..=input.numpoints - q_pts {
        let mut quadrant_set = std::collections::HashSet::new();
        for j in 0..q_pts {
            let quad = get_quadrant(input.x[i + j], input.y[i + j]);
            quadrant_set.insert(quad);
        }
        if quadrant_set.len() > quads {
            return true;
        }
    }
    false
}

fn get_quadrant(x: f64, y: f64) -> u8 {
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x < 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

fn lic6(input: &DecideInput) -> bool {
    for i in 0..input.numpoints - 1 {
        if realcompare(input.x[i + 1] - input.x[i], 0.0) == "LT" {
            return true;
        }
    }
    false
}

fn lic7(input: &DecideInput) -> bool {
    let n_pts = input.parameters.n_pts;
    let dist = input.parameters.dist;

    if input.numpoints < 3 || n_pts > input.numpoints {
        return false;
    }

    for i in 0..=input.numpoints - n_pts {
        let p_first = (input.x[i], input.y[i]);
        let p_last = (input.x[i + n_pts - 1], input.y[i + n_pts - 1]);

        let mut found = false;
        for k in 0..n_pts {
            let p = (input.x[i + k], input.y[i + k]);
            let d = point_to_line_distance(p, p_first, p_last);
            if realcompare(d, dist) == "GT" {
                found = true;
                break;
            }
        }
        if found {
            return true;
        }
    }
    false
}

fn point_to_line_distance(p: (f64, f64), p1: (f64, f64), p2: (f64, f64)) -> f64 {
    let (x, y) = p;
    let (x1, y1) = p1;
    let (x2, y2) = p2;

    if realcompare(x1, x2) == "EQ" && realcompare(y1, y2) == "EQ" {
        return ((x - x1).powi(2) + (y - y1).powi(2)).sqrt();
    }

    let num = ((y2 - y1) * x - (x2 - x1) * y + x2 * y1 - y2 * x1).abs();
    let denom = ((y2 - y1).powi(2) + (x2 - x1).powi(2)).sqrt();
    num / denom
}

fn lic8(input: &DecideInput) -> bool {
    let k_pts = input.parameters.k_pts;
    let length1 = input.parameters.length1;

    if input.numpoints < 3 {
        return false;
    }

    for i in 0..input.numpoints {
        let j = i + k_pts + 1;
        if j >= input.numpoints {
            break;
        }
        let dx = input.x[j] - input.x[i];
        let dy = input.y[j] - input.y[i];
        let dist = (dx * dx + dy * dy).sqrt();
        if realcompare(dist, length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic9(input: &DecideInput) -> bool {
    let a_pts = input.parameters.a_pts;
