fn lic12(input: &DecideInput) -> bool {
    let g_pts = input.parameters.g_pts;

    if input.numpoints < 3 {
        return false;
    }

    for i in 0..input.numpoints {
        let j = i + g_pts + 1;
        if j >= input.numpoints {
            break;
        }
        if realcompare(input.x[j] - input.x[i], 0.0) == "LT" {
            return true;
        }
    }
    false
}

fn lic13(input: &DecideInput) -> bool {
    let k_pts = input.parameters.k_pts;
    let length1 = input.parameters.length1;
    let length2 = input.parameters.length2;

    if input.numpoints < 3 {
        return false;
    }

    let mut found_greater = false;
    let mut found_less = false;

    for i in 0..input.numpoints {
        let j = i + k_pts + 1;
        if j >= input.numpoints {
            break;
        }
        let dx = input.x[j] - input.x[i];
        let dy = input.y[j] - input.y[i];
        let dist = (dx * dx + dy * dy).sqrt();

        if realcompare(dist, length1) == "GT" {
            found_greater = true;
        }
        if realcompare(dist, length2) == "LT" {
            found_less = true;
        }
    }

    found_greater && found_less
}

fn lic14(input: &DecideInput) -> bool {
    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let radius1 = input.parameters.radius1;
    let radius2 = input.parameters.radius2;

    if input.numpoints < 5 {
        return false;
    }

    let mut found_not_contained = false;
    let mut found_contained = false;

    for i in 0..input.numpoints {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        if k >= input.numpoints {
            break;
        }
        let p1 = (input.x[i], input.y[i]);
        let p2 = (input.x[j], input.y[j]);
        let p3 = (input.x[k], input.y[k]);

        if !can_contain_in_circle(p1, p2, p3, radius1) {
            found_not_contained = true;
        }
        if can_contain_in_circle(p1, p2, p3, radius2) {
            found_contained = true;
        }
    }

    found_not_contained && found_contained
}

